// AI-powered transaction categorization logic
const transaction = $input.first().json;

// Extract transaction details
const description = transaction.description.toLowerCase();
const amount = Math.abs(transaction.amount);

// Category mapping rules
const categoryRules = {
  food: [
    'restaurant', 'cafe', 'pizza', 'burger', 'food', 'grocery', 'supermarket',
    'mcdonalds', 'kfc', 'subway', 'starbucks', 'dominos', 'uber eats', 'doordash'
  ],
  transport: [
    'uber', 'taxi', 'bus', 'train', 'gas', 'fuel', 'parking', 'metro',
    'lyft', 'car', 'vehicle', 'transport', 'airline', 'flight'
  ],
  shopping: [
    'amazon', 'ebay', 'walmart', 'target', 'mall', 'store', 'shop',
    'clothing', 'fashion', 'electronics', 'purchase'
  ],
  utilities: [
    'electric', 'water', 'gas', 'internet', 'phone', 'mobile', 'wifi',
    'utility', 'bill', 'power', 'energy'
  ],
  entertainment: [
    'netflix', 'spotify', 'movie', 'cinema', 'game', 'entertainment',
    'subscription', 'streaming', 'music', 'youtube', 'disney'
  ],
  health: [
    'hospital', 'doctor', 'pharmacy', 'medical', 'health', 'clinic',
    'medicine', 'dental', 'insurance'
  ],
  housing: [
    'rent', 'mortgage', 'property', 'home', 'house', 'apartment',
    'maintenance', 'repair'
  ]
};

// Find matching category
let detectedCategory = 'misc'; // default
let confidence = 0;

for (const [category, keywords] of Object.entries(categoryRules)) {
  const matches = keywords.filter(keyword => description.includes(keyword));
  if (matches.length > 0) {
    const categoryConfidence = matches.length / keywords.length;
    if (categoryConfidence > confidence) {
      detectedCategory = category;
      confidence = categoryConfidence;
    }
  }
}

// Amount-based adjustments
if (amount > 1000 && detectedCategory === 'misc') {
  detectedCategory = 'housing'; // Large amounts often housing
} else if (amount < 10 && description.includes('coffee')) {
  detectedCategory = 'food';
}

// Return categorized transaction
return {
  transactionId: transaction.id,
  originalCategory: transaction.category,
  suggestedCategory: detectedCategory,
  confidence: Math.round(confidence * 100),
  description: transaction.description,
  amount: transaction.amount,
  reasoning: `Detected '${detectedCategory}' based on keywords in description`
};
